import json, re
with open('data/output/benchmark/task_a/REDACTED.jsonl') as f:
    lines = [json.loads(l) for l in f]
tool_re = re.compile(r'<tool_call>(.*?)</tool_call>', re.S)
issues=[]
for s in lines:
    cid=s['cid'] if 'cid' in s else s['conversation_id']
    schema_names = {t.get('name') or t.get('function',{}).get('name') for t in s['tool_schemas']}
    roles=[m['role'] for m in s['messages']]
    for m in s['messages']:
        for raw in tool_re.findall(m['content']):
            try:
                d=json.loads(raw.strip())
            except Exception as e:
                issues.append(f'{cid}: bad tool_call JSON: {raw[:60]!r}'); continue
            nm=d.get('name')
            if schema_names and nm not in schema_names:
                issues.append(f'{cid}: tool {nm!r} not in schemas {schema_names}')
    # role alternation sanity: no two consecutive user turns
print('Tool JSON / schema issues:', len(issues))
for x in issues[:30]: print(' -',x)
print()
# behavior label spot check: show one of each behavior (non-cooperative)
import collections
seen=set()
for s in lines:
    b=s['user_behavior']
    if b!='cooperative' and b not in seen:
        seen.add(b)
        print('=== behavior:', b, '| domain:', s['domain'], '| lang:', s['language'], '| id:', s['conversation_id'],'===')
        for m in s['messages']:
            if m['role']=='user':
                print('  [user]', m['content'][:160])
        print()
"

