import json, re, collections

PATH='data/output/benchmark/task_a/REDACTED.jsonl'
STATE_RE = re.compile(r'\[STATE:\s*([A-Za-z_][A-Za-z0-9_]*)\s*(?:->|→)\s*([A-Za-z_][A-Za-z0-9_]*)\s*\]')
TOOL_RE = re.compile(r'<tool_call>\s*(\{.*?\})\s*</tool_call>', re.DOTALL)

samples=[json.loads(l) for l in open(PATH)]
print(f"Loaded {len(samples)} samples\n")

issues=[]
arrow_uni=arrow_ascii=0
behav=collections.Counter()
lang=collections.Counter()
init=collections.Counter()
src=collections.Counter()
domains=collections.Counter()
ntools_dist=collections.Counter()
nstates_dist=[]
self_loops_total=0; trans_total=0
undeclared_nonloop=0

for s in samples:
    cid=s['conversation_id']
    wg=s['workflow_graph']
    declared={(t['from'],t['to']) for t in wg['transitions']}
    states=set(wg['states'])
    gt=s['ground_truth']
    behav[s['user_behavior']]+=1
    lang[s['language']]+=1
    init[s['conversation_initiator']]+=1
    src[s['generation_source']]+=1
    domains[s['domain']]+=1
    ntools_dist[s['num_tools']]+=1
    nstates_dist.append(s['num_states'])

    # --- L4 spec checks ---
    if s['complexity_level']!='L4': issues.append(f"{cid}: complexity_level={s['complexity_level']}")
    if not (12<=s['num_states']<=16): issues.append(f"{cid}: num_states={s['num_states']} outside L4 path_len(12,16)")
    if s['num_tools']<6: issues.append(f"{cid}: num_tools={s['num_tools']} below L4 floor 6")
    if s['chain_depth']<3: issues.append(f"{cid}: chain_depth={s['chain_depth']} below L4 spec 3")

    # consistency num_states vs graph
    if s['num_states']!=len(wg['states']): issues.append(f"{cid}: num_states {s['num_states']} != len(states) {len(wg['states'])}")
    if s['num_tools']!=len(s['tool_schemas']): issues.append(f"{cid}: num_tools {s['num_tools']} != len(tool_schemas) {len(s['tool_schemas'])}")

    # initial/terminal in states
    if wg['initial'] not in states: issues.append(f"{cid}: initial {wg['initial']} not in states")
    for t in wg['terminal']:
        if t not in states: issues.append(f"{cid}: terminal {t} not in states")

    # transitions reference valid states
    for tr in wg['transitions']:
        if tr['from'] not in states: issues.append(f"{cid}: transition from {tr['from']} not in states")
        if tr['to'] not in states: issues.append(f"{cid}: transition to {tr['to']} not in states")

    # back-edges (loops) present? L4 num_loops (1,1) => >=1 back-edge
    order={st:i for i,st in enumerate(wg['states'])}
    backedges=[(t['from'],t['to']) for t in wg['transitions'] if order.get(t['to'],99)<=order.get(t['from'],-1) and t['from']!=t['to']]
    if len(backedges)<1: issues.append(f"{cid}: no back-edge found (L4 requires >=1 loop)")

    # --- ground_truth state_sequence legality ---
    for tr in gt['state_sequence']:
        trans_total+=1
        fr,to=tr['from'],tr['to']
        if fr==to:
            self_loops_total+=1
        elif (fr,to) not in declared:
            undeclared_nonloop+=1
            issues.append(f"{cid}: GT transition {fr}->{to} NOT in declared edges")
        if fr not in states: issues.append(f"{cid}: GT state {fr} not in graph states")
        if to not in states: issues.append(f"{cid}: GT state {to} not in graph states")

    # terminal reached
    if gt['terminal_state'] not in wg['terminal']:
        issues.append(f"{cid}: GT terminal {gt['terminal_state']} not in graph terminals")
    if gt['state_sequence'] and gt['state_sequence'][-1]['to']!=gt['terminal_state']:
        issues.append(f"{cid}: last GT transition ends {gt['state_sequence'][-1]['to']} != terminal {gt['terminal_state']}")

    # --- message-level: STATE annotations parse & match GT sequence ---
    msg_states=[]
    for m in s['messages']:
        if m['role']=='assistant':
            for mt in STATE_RE.finditer(m['content']):
                msg_states.append((mt.group(1),mt.group(2)))
                if '→' in m['content'][mt.start():mt.end()]: arrow_uni+=1
                else: arrow_ascii+=1
    gt_seq=[(t['from'],t['to']) for t in gt['state_sequence']]
    if msg_states!=gt_seq:
        issues.append(f"{cid}: msg STATE seq (len {len(msg_states)}) != GT state_sequence (len {len(gt_seq)})")

    # --- role sequencing ---
    roles=[m['role'] for m in s['messages']]
    if roles[0]!='system': issues.append(f"{cid}: first role {roles[0]} != system")
    # outbound => messages[1] assistant; inbound => messages[1] user
    if s['conversation_initiator']=='agent' and roles[1]!='assistant':
        issues.append(f"{cid}: outbound but messages[1]={roles[1]} != assistant")
    if s['conversation_initiator']=='user' and roles[1]!='user':
        issues.append(f"{cid}: inbound but messages[1]={roles[1]} != user")

    # --- tool_call JSON validity in messages ---
    tool_schema_names={ts['function']['name'] for ts in s['tool_schemas']}
    for m in s['messages']:
        for tc in TOOL_RE.finditer(m['content']):
            try:
                obj=json.loads(tc.group(1))
            except Exception as e:
                issues.append(f"{cid}: invalid tool_call JSON: {e}")
                continue
            name=obj.get('name')
            if name and name not in tool_schema_names:
                issues.append(f"{cid}: tool_call '{name}' not in tool_schemas")

print("=== L4 SPEC DISTRIBUTIONS ===")
print("num_states:", sorted(set(nstates_dist)), "min",min(nstates_dist),"max",max(nstates_dist))
print("num_tools dist:", dict(sorted(ntools_dist.items())))
print("language:", dict(lang))
print("initiator:", dict(init))
print("source:", dict(src))
print("behavior:", dict(behav))
print("domains:", dict(domains))
print()
print(f"arrows: unicode={arrow_uni} ascii={arrow_ascii}")
print(f"GT transitions total={trans_total}  self_loops={self_loops_total} ({100*self_loops_total/trans_total:.0f}%)  undeclared_nonloop={undeclared_nonloop}")
print()
print(f"=== ISSUES: {len(issues)} ===")
for i in issues[:60]:
    print(" -",i)
