            if re.search(r'error|fail|ขัดข้อง|ไม่สำเร็จ|unavailable', c, re.I): saw_error=True
        elif m['role']=='user':
            for v in re.findall(r'[A-Z]{2,}[-_]?\w*\d[\w-]*', c):
                user_supplied.add(v)
        elif m['role']=='assistant':
            for tc in TOOL_RE.finditer(c):
                try: call=json.loads(tc.group(1))
                except: continue
                for v in re.findall(r'[A-Z]{2,}[-_]?\w*\d[\w-]*', json.dumps(call['arguments'])):
                    if v in produced and v not in user_supplied:
                        propagated_here.append((call['name'],v))
    if propagated_here:
        prop_samples+=1
        if len(prop_examples)<5: prop_examples.append((s['conversation_id'],propagated_here[:3]))
    if saw_error: recovery_samples+=1

print(f"samples with tool-response→later-call propagation: {prop_samples}/50")
for cid,ex in prop_examples:
    print(f"  {cid}: {ex}")
print()
print(f"samples exhibiting a tool error/recovery turn: {recovery_samples}/50 (L4 include_recovery=True)")

# branch coverage: L4 num_branches (3,5) => count off-spine branch transitions (states with >1 outgoing edge)
branchy=0
for s in samples:
    wg=s['workflow_graph']
    outdeg=collections.Counter(t['from'] for t in wg['transitions'])
    branch_states=[st for st,d in outdeg.items() if d>1]
    if len(branch_states)>=3: branchy+=1
print(f"\nsamples with >=3 branching states (L4 num_branches 3-5): {branchy}/50")
